import { useEffect, useState } from "react";
import { ShieldCheck, Clock, AlertTriangle, Server, Activity, Zap } from 'lucide-react';

export default function SystemStats() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Mock danych - podłącz potem API
    setTimeout(() => {
      setStats({
        uptime: 240,
        capture: { kernel_packets: 1024 },
        flow: { tcp: 12 },
        detect: { alert: 5, alert_queue_overflow: 1 },
      });
      setLoading(false);
    }, 500);
  }, []);

  if (loading) return <p className="text-gray-500">Ładowanie statystyk systemu...</p>;

  const items = [
    { label: "Uptime (s)", value: stats.uptime, icon: Clock, color: "bg-blue-100 text-blue-600" },
    { label: "Pakiety z jądra", value: stats.capture.kernel_packets, icon: Server, color: "bg-yellow-100 text-yellow-600" },
    { label: "Sesje TCP", value: stats.flow.tcp, icon: Activity, color: "bg-green-100 text-green-600" },
    { label: "Liczba alertów", value: stats.detect.alert, icon: AlertTriangle, color: "bg-red-100 text-red-600" },
    { label: "Alert Queue Overflow", value: stats.detect.alert_queue_overflow, icon: Zap, color: "bg-orange-100 text-orange-600" },
  ];

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
      {items.map(({ label, value, icon: Icon, color }, i) => (
        <div key={i} className="flex items-center p-4 bg-white rounded-xl shadow border-l-4 border-gray-200">
          <div className={`w-12 h-12 flex items-center justify-center rounded-full mr-4 ${color}`}>
            <Icon size={24} />
          </div>
          <div>
            <h4 className="text-sm text-gray-500">{label}</h4>
            <p className="text-2xl font-semibold text-gray-800">{value}</p>
          </div>
        </div>
      ))}
    </div>
  );
}
